import { useNavigate } from "react-router-dom";
import booksData from "../data/booksData";
import "./styles/LibrarianBooks.css";

function LibrarianBooks() {
  /* ✅ HOOKS FIRST */
  const navigate = useNavigate();

  /* ✅ GET GENRE */
  const rawGenre = localStorage.getItem("genre"); 
  const genre = rawGenre
    ? rawGenre.charAt(0).toUpperCase() + rawGenre.slice(1).toLowerCase()
    : null;

  /* ✅ FETCH BOOKS */
  const books = genre ? booksData[genre] : null;

  /* ✅ SAFETY CHECK */
  if (!genre || !books) {
    return (
      <div className="books-page">
        <h2 className="books-title">Genre not found</h2>
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    );
  }

  return (
    <div className="books-page">
      <h1 className="books-title">Manage {genre} Books</h1>

      {books.length === 0 ? (
        <p>No books found for this genre.</p>
      ) : (
        <div className="books-grid">
          {books.map((book, i) => (
            <div key={i} className="book-card">
              <img src={book.cover} alt={book.title} />
              <h3>{book.title}</h3>
              <p>{book.author}</p>
            </div>
          ))}
        </div>
      )}

      <div className="action-buttons">
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    </div>
  );
}

export default LibrarianBooks;
